-- 2) Añadirlas al EVENTO ACTIVO (Jukebox / Tinder / Batalla)
--    event_id = la "Fiesta 12/06" activa ahora mismo.
insert into public.event_tracks
  (tenant_id, event_id, spotify_id, title, artist, cover_image_url, total_votes, is_played)
select g.tenant_id, '3a1acf9a-c909-44d2-9ad3-86c51e773be4',
       g.spotify_id, g.title, g.artist, g.cover_image_url, 0, false
from public.global_tracks g
where g.tenant_id = (select id from public.tenants where slug='lapocha')
on conflict (event_id, spotify_id) do nothing;

-- 3) Comprobacion
select
  (select count(*) from public.global_tracks
     where tenant_id=(select id from public.tenants where slug='lapocha')) as global_total,
  (select count(*) from public.event_tracks
     where event_id='3a1acf9a-c909-44d2-9ad3-86c51e773be4') as evento_total;
